import{_ as e,o as a,c as l,ag as d}from"./chunks/framework.DTiDeF2Q.js";const m=JSON.parse('{"title":"インタラクティブエイリアス | Dotfiles (JA)","titleTemplate":":title","description":"破壊的操作の前に確認プロンプトを追加する安全なシェルエイリアス。rm、mv、cpの誤操作を防止。","frontmatter":{"title":"インタラクティブエイリアス | Dotfiles","description":"破壊的操作の前に確認プロンプトを追加する安全なシェルエイリアス。rm、mv、cpの誤操作を防止。","lang":"ja-JP","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"インタラクティブエイリアス preview","canonical":"/ja/aliases/interactive/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"インタラクティブエイリアス","pageType":"docs","schemaType":"WebPage","metaTitle":"インタラクティブエイリアス - Dotfiles (JP)","permalink":"/ja/aliases/interactive/","sidebar":true,"meta":[{"name":"keywords","content":"interactive aliases, shell safety, rm confirmation, cp interactive, mv prompt, dotfiles"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"破壊的操作の前に確認プロンプトを追加する安全なシェルエイリアス。rm、mv、cpの誤操作を防止。"},{"name":"twitter:title","content":"インタラクティブエイリアス - Dotfiles"},{"name":"og:title","content":"インタラクティブエイリアス - Dotfiles"},{"name":"og:description","content":"破壊的操作の前に確認プロンプトを追加する安全なシェルエイリアス。rm、mv、cpの誤操作を防止。"},{"name":"og:image:alt","content":"Dotfiles - シェルライフにフィットするシンプルな設計"},{"name":"og:locale","content":"ja_JP"}]},"headers":[],"relativePath":"ja/aliases/interactive/index.md","filePath":"ja/aliases/interactive/index.md","lastUpdated":1773010926000}'),i={name:"ja/aliases/interactive/index.md"};function n(r,t,o,s,c,h){return a(),l("div",null,[...t[0]||(t[0]=[d('<h1 id="インタラクティブエイリアス" tabindex="-1">インタラクティブエイリアス <a class="header-anchor" href="#インタラクティブエイリアス" aria-label="Permalink to &quot;インタラクティブエイリアス&quot;">​</a></h1><p>破壊的操作の前に確認プロンプトを表示する安全なシェルコマンド。</p><h2 id="概要" tabindex="-1">概要 <a class="header-anchor" href="#概要" aria-label="Permalink to &quot;概要&quot;">​</a></h2><p>インタラクティブエイリアスは、ファイルを永続的に変更または削除する可能性のある一般的なシェルコマンドに確認プロンプトを追加します。<code>interactive.aliases.sh</code>で定義され、Chezmoiによって自動的にロードされます。潜在的に破壊的な操作を実行する前にユーザー確認を要求することで、誤ったデータ損失を防ぎます。</p><h2 id="リファレンス" tabindex="-1">リファレンス <a class="header-anchor" href="#リファレンス" aria-label="Permalink to &quot;リファレンス&quot;">​</a></h2><h3 id="ファイル操作" tabindex="-1">ファイル操作 <a class="header-anchor" href="#ファイル操作" aria-label="Permalink to &quot;ファイル操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">エイリアス</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>cp</code></td><td style="text-align:left;">ファイルとディレクトリを対話的にコピー。上書き前に確認し、詳細出力を表示</td></tr><tr><td style="text-align:left;"><code>mv</code></td><td style="text-align:left;">ファイルを対話的に移動または名前変更。上書き前に確認し、詳細出力を表示</td></tr><tr><td style="text-align:left;"><code>ln</code></td><td style="text-align:left;">シンボリックリンクを対話的に作成。上書き前に確認し、詳細出力を表示</td></tr></tbody></table><h3 id="ファイル削除" tabindex="-1">ファイル削除 <a class="header-anchor" href="#ファイル削除" aria-label="Permalink to &quot;ファイル削除&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">エイリアス</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>rm</code></td><td style="text-align:left;">ファイルまたはディレクトリを対話的に削除。各削除前に確認し、詳細出力を表示</td></tr><tr><td style="text-align:left;"><code>del</code></td><td style="text-align:left;">ファイルまたはディレクトリを対話的かつ再帰的に削除。各削除前に確認し、詳細出力を表示</td></tr><tr><td style="text-align:left;"><code>zap</code></td><td style="text-align:left;"><code>rm</code>のエイリアス。ファイルまたはディレクトリを対話的に削除</td></tr></tbody></table><h3 id="ゴミ箱管理" tabindex="-1">ゴミ箱管理 <a class="header-anchor" href="#ゴミ箱管理" aria-label="Permalink to &quot;ゴミ箱管理&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">エイリアス</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>bin</code></td><td style="text-align:left;">ゴミ箱ディレクトリ（<code>~/.Trash</code>）内のすべてのファイルを強制的に再帰的に削除</td></tr></tbody></table><h3 id="パーミッションとユーティリティ" tabindex="-1">パーミッションとユーティリティ <a class="header-anchor" href="#パーミッションとユーティリティ" aria-label="Permalink to &quot;パーミッションとユーティリティ&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">エイリアス</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>chmod</code></td><td style="text-align:left;">ファイルまたはディレクトリのパーミッションを詳細出力で変更</td></tr><tr><td style="text-align:left;"><code>chown</code></td><td style="text-align:left;">ファイルまたはディレクトリの所有者とグループを詳細出力で変更</td></tr><tr><td style="text-align:left;"><code>diff</code></td><td style="text-align:left;">2つのファイルの差分を統合された形式で比較して表示</td></tr><tr><td style="text-align:left;"><code>grep</code></td><td style="text-align:left;">ファイルまたは出力内のパターンを検索し、行番号を表示して大文字小文字を区別しない</td></tr><tr><td style="text-align:left;"><code>mkdir</code></td><td style="text-align:left;">必要に応じて親ディレクトリを作成し、詳細出力で新しいディレクトリを作成</td></tr></tbody></table>',13)])])}const x=e(i,[["render",n]]);export{m as __pageData,x as default};
